const input = $('When Executed by Another Workflow').item.json;

// Verifica se valor é vazio/nulo/string 'null'
const isEmpty = (v) => !v || String(v).trim() === '' || String(v).trim().toLowerCase() === 'null' || String(v).trim().toLowerCase() === 'undefined';

// Escapa aspas simples para uso seguro em SQL
const escapeSql = (str) => {
  if (isEmpty(str)) return '';
  return String(str).trim().replace(/'/g, "''");
};

// Remove prefixos de médico (Dr., Dra., etc) + escapa
const limparNomeMedico = (nome) => {
  if (isEmpty(nome)) return '';
  const limpo = String(nome).replace(/^(dr\.?|dra\.?|doutor|doutora|médico|medico)\s+/i, '').trim();
  return escapeSql(limpo);
};

// Normaliza data para YYYY-MM-DD
const normalizarData = (d) => {
  if (isEmpty(d)) return '';
  d = String(d).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(d)) return d;
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(d)) return d.split('/').reverse().join('-');
  return d;
};

// Normaliza horário para HH:MM
const normalizarHorario = (h) => {
  if (isEmpty(h)) return '';
  h = String(h).trim().replace(/h/i, ':').replace(/:$/, ':00').replace(/^(\d):/, '0$1:');
  return h;
};

// CPF limpo — obrigatório
const cpfLimpo = (input.cpf_paciente || '').replace(/[^0-9]/g, '');
if (!cpfLimpo || cpfLimpo.length !== 11) {
  throw new Error(`CPF inválido ou ausente: '${input.cpf_paciente}'. O agendamento não pode continuar sem CPF válido.`);
}

// Nome — obrigatório (NOT NULL na tabela pacientes)
// Se não vier do agente, usa fallback para não travar o fluxo
const nomePaciente = isEmpty(input.nome_paciente)
  ? `Paciente ${cpfLimpo}`
  : escapeSql(input.nome_paciente);

return [{
  json: {
    tipo_atendimento:  String(input.tipo_atendimento || ''),
    nome_paciente:     nomePaciente,
    celular_paciente:  isEmpty(input.celular_paciente) ? '' : String(input.celular_paciente).replace(/[^0-9]/g, ''),
    cpf_limpo:         cpfLimpo,
    data_atendimento:  normalizarData(input.data_atendimento),
    horario:           normalizarHorario(input.horario),
    nome_medico_sql:   limparNomeMedico(input.nome_medico),
    nome_convenio_sql: escapeSql(input.nome_convenio),
    is_particular:     isEmpty(input.nome_convenio) || input.nome_convenio.toLowerCase().trim() === 'particular'
  }
}];
